import React, { useState } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";

const Navbar = () => {
  const { user, logout, isAuthenticated } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [menuOpen, setMenuOpen] = useState(false);

  const handleLogout = () => {
    logout();
    navigate("/");
    setMenuOpen(false);
  };

  const isActive = (path) => location.pathname === path;

  return (
    <nav className="navbar navbar-expand-lg navbar-dark-custom sticky-top">
      <div className="container py-2">
        <Link className="navbar-brand d-flex align-items-center gap-3 fw-bold" to="/">
          <span
            className="d-inline-flex align-items-center justify-content-center"
            style={{
              width: 40,
              height: 40,
              borderRadius: 14,
              background: "linear-gradient(135deg, rgba(96,165,250,0.18), rgba(45,212,191,0.16))",
              border: "1px solid rgba(96,165,250,0.2)",
              color: "var(--primary)",
              fontFamily: "var(--font-mono)",
              fontSize: "0.9rem",
            }}
          >
            CL
          </span>
          <div>
            <div style={{ color: "var(--text)", lineHeight: 1 }}>CodeLearn</div>
            <div style={{ color: "var(--text-muted)", fontSize: "0.72rem", fontWeight: 600, letterSpacing: "0.12em", textTransform: "uppercase" }}>
              Learning Platform
            </div>
          </div>
        </Link>

        <button
          className="navbar-toggler border-0"
          type="button"
          onClick={() => setMenuOpen((prev) => !prev)}
          style={{ color: "var(--text-secondary)" }}
        >
          <i className={`bi ${menuOpen ? "bi-x-lg" : "bi-list"} fs-5`} />
        </button>

        <div className={`collapse navbar-collapse ${menuOpen ? "show" : ""}`}>
          <ul className="navbar-nav mx-auto mb-2 mb-lg-0 gap-lg-2">
            <li className="nav-item">
              <Link
                className={`nav-link px-3 py-2 ${isActive("/") ? "active" : ""}`}
                to="/"
                onClick={() => setMenuOpen(false)}
                style={{ color: isActive("/") ? "var(--text)" : "var(--text-secondary)", fontWeight: 700 }}
              >
                Catalog
              </Link>
            </li>
            {isAuthenticated && (
              <li className="nav-item">
                <Link
                  className={`nav-link px-3 py-2 ${isActive("/my-courses") ? "active" : ""}`}
                  to="/my-courses"
                  onClick={() => setMenuOpen(false)}
                  style={{ color: isActive("/my-courses") ? "var(--text)" : "var(--text-secondary)", fontWeight: 700 }}
                >
                  My Learning
                </Link>
              </li>
            )}
          </ul>

          <div className="d-flex align-items-center gap-2 mt-3 mt-lg-0">
            {isAuthenticated ? (
              <>
                <div className="d-flex align-items-center gap-3 me-lg-2 px-2 py-1" style={{ borderRadius: 999, background: "rgba(8,16,31,0.45)", border: "1px solid var(--border)" }}>
                  <div
                    style={{
                      width: 36,
                      height: 36,
                      borderRadius: 12,
                      background: "linear-gradient(135deg, var(--primary), var(--accent))",
                      display: "grid",
                      placeItems: "center",
                      color: "#08101f",
                      fontWeight: 800,
                    }}
                  >
                    {user?.name?.charAt(0)?.toUpperCase()}
                  </div>
                  <div className="d-none d-md-block">
                    <div style={{ color: "var(--text)", fontSize: "0.9rem", fontWeight: 700 }}>
                      {user?.name?.split(" ")[0]}
                    </div>
                    <div style={{ color: "var(--text-muted)", fontSize: "0.72rem" }}>Active learner</div>
                  </div>
                </div>
                <button className="btn btn-outline-custom btn-sm px-3 py-2" onClick={handleLogout}>
                  Sign Out
                </button>
              </>
            ) : (
              <>
                <Link to="/login" className="btn btn-outline-custom btn-sm px-3 py-2" onClick={() => setMenuOpen(false)}>
                  Log In
                </Link>
                <Link to="/signup" className="btn btn-primary-custom btn-sm px-3 py-2" onClick={() => setMenuOpen(false)}>
                  Create Account
                </Link>
              </>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
